proof_block:
// Each "*_unchanged*" predicate in the ensures is a `forall|x|` with a
// single-run trigger like `pre_self_.get_proc(p)` / `pre_self_.get_container(c)`
// / `pre_self_.get_thread(t)`. Those triggers ARE shared between the two
// runs (both runs reference the same `pre_self_`), but the BODY of each
// `forall` mentions only `post1_self_` (resp. `post2_self_`), so z3 keeps
// the two ensures-conjuncts skolemised independently and never derives a
// pointwise post1 vs post2 equality. Each `assert forall ... by { ... }`
// below re-issues the forall with a fused trigger (`pre_self_.get_*`) and
// concludes a post1-vs-post2 pointwise equality, which Verus discharges by
// chaining the two per-run instances. The trailing scalar/extensional
// assertions then close `det_drop_endpoint_equal`'s map-extensionality
// goals on `container_perms@ / process_perms@ / thread_perms@`.

// ---- proc_dom + processes_unchanged (both runs) -> get_proc pointwise eq.
assert(post1_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post2_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());
assert forall|p: ProcPtr| #![trigger pre_self_.get_proc(p)]
    pre_self_.proc_dom().contains(p) implies
        post1_self_.get_proc(p) =~= post2_self_.get_proc(p) by {
    assert(post1_self_.proc_dom().contains(p));
    assert(post2_self_.proc_dom().contains(p));
};

// ---- container_dom equal in both runs (from ensures directly).
assert(post1_self_.container_dom() == pre_self_.container_dom());
assert(post2_self_.container_dom() == pre_self_.container_dom());
assert(post1_self_.container_dom() =~= post2_self_.container_dom());

// containers_tree_unchanged + containers_owned_proc_unchanged are
// universal (no exception set) over the whole dom, so for every c in
// container_dom each of the 7 listed fields equals pre's in both runs,
// hence equals between runs.
assert forall|c: ContainerPtr| #![trigger pre_self_.get_container(c)]
    pre_self_.container_dom().contains(c) implies
        post1_self_.get_container(c).parent
            =~= post2_self_.get_container(c).parent
        && post1_self_.get_container(c).children
            =~= post2_self_.get_container(c).children
        && post1_self_.get_container(c).uppertree_seq
            =~= post2_self_.get_container(c).uppertree_seq
        && post1_self_.get_container(c).subtree_set
            =~= post2_self_.get_container(c).subtree_set
        && post1_self_.get_container(c).depth
            =~= post2_self_.get_container(c).depth
        && post1_self_.get_container(c).root_process
            =~= post2_self_.get_container(c).root_process
        && post1_self_.get_container(c).owned_procs
            =~= post2_self_.get_container(c).owned_procs by {
    assert(post1_self_.container_dom().contains(c));
    assert(post2_self_.container_dom().contains(c));
};

// ---- thread_dom equal in both runs (from ensures directly).
assert(post1_self_.thread_dom() == pre_self_.thread_dom());
assert(post2_self_.thread_dom() == pre_self_.thread_dom());
assert(post1_self_.thread_dom() =~= post2_self_.thread_dom());

// threads_unchanged_except {thread_ptr} for both runs -> full thread
// equality off `thread_ptr`.
assert forall|t: ThreadPtr| #![trigger pre_self_.get_thread(t)]
    pre_self_.thread_dom().contains(t) && t != thread_ptr implies
        post1_self_.get_thread(t) =~= post2_self_.get_thread(t) by {
    assert(post1_self_.thread_dom().contains(t));
    assert(post2_self_.thread_dom().contains(t));
    assert(!(set![thread_ptr].contains(t)));
};

// thread_ptr-specific field equalities (directly pinned by ensures for
// both runs, so they match between runs).
assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors@
    =~= post2_self_.get_thread(thread_ptr).endpoint_descriptors@);
assert(post1_self_.get_thread(thread_ptr).blocking_endpoint_index
    =~= post2_self_.get_thread(thread_ptr).blocking_endpoint_index);
assert(post1_self_.get_thread(thread_ptr).state
    == post2_self_.get_thread(thread_ptr).state);
assert(post1_self_.get_thread(thread_ptr).owning_proc
    == post2_self_.get_thread(thread_ptr).owning_proc);

// ---- Lift the dom equalities to the underlying `*_perms@` Maps.
// `container_dom()` / `proc_dom()` / `thread_dom()` are inline-equal to
// `*_perms@.dom()`, so this is just a re-statement that gives z3 the
// shape it needs for the `Map<_, _>` extensionality check inside
// `det_drop_endpoint_equal`.
assert(post1_self_.container_perms@.dom() =~= post2_self_.container_perms@.dom());
assert(post1_self_.thread_perms@.dom() =~= post2_self_.thread_perms@.dom());
assert(post1_self_.process_perms@.dom() =~= post2_self_.process_perms@.dom());
